extra_questions = [
    normalize_question(qid, q, opts, a, ex, source_tag, source_label, 'paraphrase', [tag])
    for qid, tag, q, opts, a, ex, source_tag, source_label in manual_questions
]

# de-duplicate by normalized question text
seen = set()
questions = []
for q in base_questions + adapted_from_qdata + extra_questions:
    key = ' '.join(q['q'].lower().split())
    if key in seen:
        continue
    seen.add(key)
    questions.append(q)

source_index = {q['id']: q for q in questions}

def ids_for(*tags):
    wanted = set(tags)
    return [q['id'] for q in questions if wanted.intersection(q['tags'])]

def pick(*ids):
    return [qid for qid in ids if qid in source_index]

